void removeEvenIndices(ArrayList<Integer> list) {
    for (int i = 0; i < list.size(); i++) {
        if (list.get(i) % 2 == 0) {
            list.remove(i);
            i--;
        }
    }
}

class TrieNode {
    Map<Character, TrieNode> children = new HashMap<>();
    boolean end;
}

class Trie {
    private TrieNode root = new TrieNode();

    boolean startsWith(String prefix) {
        TrieNode node = root;
        for (char ch : prefix.toCharArray()) {
            node = node.children.get(ch);
            if (node == null) return false;
        }
        return true;
    }
}

def count_subset_sum(nums, target):
    memo = {}
    def helper(i, total):
        if total == target:
            return 1
        if i == len(nums):
            return 0
        if (i, total) in memo:
            return memo[(i, total)]
        include = helper(i + 1, total + nums[i])
        exclude = helper(i + 1, total)
        memo[(i, total)] = include + exclude
        return memo[(i, total)]
    return helper(0, 0)

from collections import deque

def min_steps(grid):
    rows, cols = len(grid), len(grid[0])
    visited = [[False] * cols for _ in grid]
    q = deque([(0, 0, 0)])
    visited[0][0] = True
    while q:
        r, c, steps = q.popleft()
        if r == rows - 1 and c == cols - 1:
            return steps
        for dr, dc in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < rows and 0 <= nc < cols and not visited[nr][nc] and grid[nr][nc] == 0:
                visited[nr][nc] = True
                q.append((nr, nc, steps + 1))
    return -1

def longest(seq, i, j, memo):
    if i > j:
        return 0
    if i == j:
        return 1
    if (i, j) in memo:
        return memo[(i, j)]
    if seq[i] == seq[j]:
        memo[(i, j)] = 2 + longest(seq, i + 1, j - 1, memo)
    else:
        memo[(i, j)] = max(longest(seq, i + 1, j, memo), longest(seq, i, j - 1, memo))
    return memo[(i, j)]

import heapq

def dijkstra(graph, start):
    dist = {start: 0}
    heap = [(0, start)]
    while heap:
        d, u = heapq.heappop(heap)
        if d > dist[u]:
            continue
        for v, w in graph[u]:
            nd = d + w
            if nd < dist.get(v, float('inf')):
                dist[v] = nd
                heapq.heappush(heap, (nd, v))
    return dist

